// AGENT: Cover Letter v1.0.0 — PLACEHOLDER
// In Phase 5, for top-N listings by ATS score:
//  1. Check Redis cache (key: cl:{resume_id}:{listing_id})
//  2. If MISS: Send resume_profile + job + company_profile + career_goals to Claude 3.5 Sonnet
//  3. Generate personalized cover letter with specified tone
//  4. Validate word count (250-400 words)
//  5. Store in cover_letters table
//  6. Cache in Redis

const input = $input.first().json;
const ctx   = input.execution_context;
if (!ctx) throw new Error('[cover_letter] Missing execution_context');

const started_at = Date.now();
const topN       = parseInt($env.PIPELINE_COVER_LETTER_TOP_N) || 5;
const ats_sorted = [...(ctx.results.ats_reports || [])].sort((a, b) => b.match_score - a.match_score);
const top_jobs   = ats_sorted.slice(0, topN);

console.log(`[cover_letter] START | generating for top ${topN} listings`);

// PLACEHOLDER: Generate stub cover letters
const cover_letters = top_jobs.map((r, idx) => ({
  cover_letter_id: `cl_placeholder_${idx}_${ctx.user_id}`,
  listing_id:      r.listing_id,
  user_id:         ctx.user_id,
  content:         'PLACEHOLDER — Personalized cover letter will be generated here by Claude 3.5 Sonnet in Phase 5.',
  tone:            'formal',
  word_count:      0,
  model_used:      null,
  tokens_used:     0,
  created_at:      new Date().toISOString()
}));

ctx.results.cover_letters = cover_letters;
ctx.agents_completed.push('cover_letter');

const duration_ms = Date.now() - started_at;
console.log(`[cover_letter] COMPLETE (placeholder) | letters=${cover_letters.length}`);

return [{
  json: {
    execution_context: ctx,
    cover_letters,
    status: 'placeholder',
    agent_meta: { agent_id: 'agent-cover-letter', agent_version: '1.0.0', execution_id: ctx.execution_id, model_used: null, tokens_total: 0, duration_ms, status: 'placeholder', error: null }
  }
}];
